function Chart() {
    const { incomes, expenses } = useGlobalContext();

    // Collect unique dates from both incomes and expenses
    const allDates = [...new Set([
        ...incomes.map((inc) => dateFormat(inc.date)),
        ...expenses.map((exp) => dateFormat(exp.date))
    ])].sort(); // Sort dates if necessary

    const data = {
        labels: allDates, // Use all unique dates for labels
        datasets: [
            {
                label: 'Income',
                data: allDates.map((date) => {
                    const incomeEntry = incomes.find((inc) => dateFormat(inc.date) === date);
                    return incomeEntry ? incomeEntry.amount : 0; // Use 0 if there's no income for that date
                }),
                backgroundColor: 'green',
                tension: 0.2
            },
            {
                label: 'Expenses',
                data: allDates.map((date) => {
                    const expenseEntry = expenses.find((exp) => dateFormat(exp.date) === date);
                    return expenseEntry ? expenseEntry.amount : 0; // Use 0 if there's no expense for that date
                }),
                backgroundColor: 'red',
                tension: 0.2
            }
        ]
    };

    return (
        <ChartStyled>
            <Line data={data} />
        </ChartStyled>
    );
}


const ChartStyled = styled.div`
    background: #FCF6F9;
    border: 2px solid #FFFFFF;
    box-shadow: 0px 1px 15px rgba(0, 0, 0, 0.06);
    padding: 1rem;
    border-radius: 20px;
    height: 100%;
`;

export default Chart
